function setBothContext(ctx, key, value) {
  ctx.set(key, value);
  try { ctx.set(key, value, 'file'); } catch (error) {}
}

function publishPlans(groups) {
  setBothContext(flow, 'plans', groups);
  setBothContext(global, 'schedulePlans', groups);
  setBothContext(global, 'scheduleRaw', groups);
  setBothContext(global, 'scheduleUpdatedAt', new Date().toISOString());
  const config = global.get('controlConfig') || global.get('unifiedControlConfig');
  if (config && config.operation) {
    config.operation.scheduledControlEnabled = true;
    setBothContext(global, 'controlConfig', config);
    setBothContext(global, 'unifiedControlConfig', config);
  }
}

function storedControlConfig() {
  return getAnyContext(global, 'controlConfig') || getAnyContext(global, 'unifiedControlConfig') || getAnyContext(flow, 'controlConfig') || null;
}

function saveControlConfig(config) {
  setBothContext(global, 'controlConfig', config);
  setBothContext(global, 'unifiedControlConfig', config);
  setBothContext(flow, 'controlConfig', config);
}

const payload = parseBody(msg.req && msg.req.body !== undefined ? msg.req.body : msg.payload) || {};
const method = payload.method || payload?.data?.method || payload?.action || '';
const response = {
  code: 0,
  message: 'Success',
  version: payload.version || '1.0',
  requestId: payload.requestId || 0,
  timestamp: Math.floor(Date.now() / 1000),
  data: { code: 0, message: 'Success' }
};

let plans = getAnyContext(flow, 'plans') || getAnyContext(global, 'schedulePlans') || [];
let configToApply = null;

switch (method) {
  case 'GetControlConfig':
    response.data = { config: storedControlConfig() };
    break;
  case 'SaveControlConfig':
    if (!payload?.data?.config) {
      response.code = -5;
      response.message = 'Missing config';
      response.data = { code: -5, message: 'Missing config' };
      break;
    }
    configToApply = payload.data.config;
    saveControlConfig(configToApply);
    const restartRequired = true;
    const restart = { code: 0, message: 'OK', restartRequired, reason: 'site config changed; fixed Modbus slot topology/IP changes require NodeRedModule restart' };
    setBothContext(global, 'restartRequired', restart);
    response.data = restart;
    break;
  case 'Append': {
    const groups = normalizeToGroupArray(payload.data !== undefined ? payload.data : payload);
    const valid = validateAndSanitizeGroups(groups);
    if (!groups.length || !valid.ok) {
      response.code = -4;
      response.message = !groups.length ? 'No timed groups to append' : 'Validation failed';
      response.data = { code: response.code, message: response.message, errors: valid.errors, warnings: valid.warnings };
      break;
    }
    const incomingHasDefault = valid.groupsSanitized.some((group) => (group.timed || []).some((plan) => plan.default));
    if (incomingHasDefault) {
      plans = plans.map((group) => ({ ...group, timed: (group.timed || []).filter((plan) => !plan.default) })).filter((group) => group.timed.length);
    }
    plans = plans.concat(valid.groupsSanitized);
    publishPlans(plans);
    response.data = { code: 0, message: 'Appended', count: valid.groupsSanitized.length, warnings: valid.warnings };
    break;
  }
  case 'GetList':
    response.data = { code: 0, message: 'Success', plans: flattenPlans(plans), devices: [] };
    break;
  case 'Reset':
    plans = [];
    publishPlans(plans);
    response.data = { code: 0, message: 'Reset', count: 0 };
    break;
  case 'Delete': {
    const planID = payload?.data?.planID || payload.planID;
    if (!planID) {
      response.code = -3;
      response.message = 'Missing planID';
      response.data = { code: -3, message: 'Missing planID' };
      break;
    }
    plans = plans.map((group) => ({ ...group, timed: (group.timed || []).filter((plan) => plan.planID !== planID) })).filter((group) => group.timed.length);
    publishPlans(plans);
    response.data = { code: 0, message: 'Deleted', planID };
    break;
  }
  default: {
    const groups = normalizeToGroupArray(payload);
    const valid = validateAndSanitizeGroups(groups);
    if (!groups.length || !valid.ok) {
      response.code = -1;
      response.message = !groups.length ? 'Unknown method or empty payload' : 'Validation failed';
      response.data = { code: response.code, message: response.message, errors: valid.errors, warnings: valid.warnings };
      break;
    }
    plans = valid.groupsSanitized;
    publishPlans(plans);
    response.data = { code: 0, message: 'Saved', count: plans.length, warnings: valid.warnings };
  }
}

msg.payload = response;
if (configToApply && response.code === 0) {
  return [msg, { payload: { controlConfig: configToApply } }, { payload: { controlConfig: configToApply } }];
}
return [msg, null, null];

const cycle = global.get('lastUnifiedControlCycle') || {};
const telemetry = cycle.telemetry || {};
const now = new Date();

function numeric(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : undefined;
}

const gridPowerKw = numeric(telemetry.gridPowerKw ?? telemetry.utilityPowerKw);
const pvPowerKw = numeric(telemetry.pvPowerKw ?? telemetry.pvKw);
const pcsPowerKw = numeric(telemetry.pcsPowerKw ?? telemetry.pcsActivePowerKw);
const loadPowerKw = numeric(telemetry.loadPowerKw ?? telemetry.siteLoadKw);
const backupLoadKw = numeric(telemetry.backupLoadKw);
const batteryPowerKw = numeric(telemetry.batteryPowerKw ?? telemetry.machineStatus?.actualBatteryPowerKw);
const generatorPowerKw = numeric(telemetry.generatorPowerKw);
const generatorRunning = telemetry.generatorRunning === true;
const hasTelemetry = [gridPowerKw, pvPowerKw, pcsPowerKw, loadPowerKw, backupLoadKw, batteryPowerKw, generatorPowerKw].some((value) => typeof value === 'number') || generatorRunning;

msg.headers = { 'content-type': 'application/json' };
msg.payload = {
  data: {
    signals: {
      gridPowerKw,
      utilityPowerKw: gridPowerKw,
      pvPowerKw,
      pvKw: pvPowerKw,
      pcsPowerKw,
      pcsActivePowerKw: pcsPowerKw,
      loadPowerKw,
      siteLoadKw: loadPowerKw,
      backupLoadKw,
      batteryPowerKw,
      generatorPowerKw,
      generatorRunning
    },
    raw: {},
    source: hasTelemetry ? 'unified-control-cycle' : 'unavailable',
    updatedAt: now.toISOString()
  }
};
return msg;

const setBothContext = (ctx, key, value) => {
  ctx.set(key, value);
  try { ctx.set(key, value, 'file'); } catch (error) {}
};
let body = msg.payload || {};
if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch (error) { msg.statusCode = 400; msg.payload = { error: 'invalid JSON body' }; return [msg, null, null]; }
}
const config = body.config || body.controlConfig || body.data?.config;
if (!config || typeof config !== 'object') {
  msg.statusCode = 400;
  msg.payload = { error: 'missing config' };
  return [msg, null, null];
}
setBothContext(global, 'controlConfig', config);
setBothContext(global, 'unifiedControlConfig', config);
setBothContext(global, 'siteConfig', config);
setBothContext(flow, 'controlConfig', config);
const result = { code: 0, message: 'OK', restartRequired: true, reason: 'site config applied; topology/server-slot changes require NodeRedModule restart' };
setBothContext(global, 'restartRequired', result);
msg.headers = { 'content-type': 'application/json' };
msg.payload = { data: result };
return [msg, { payload: { controlConfig: config } }, { payload: { controlConfig: config } }];
